import { useState } from "react";

const LOGO_SRC = "data:image/jpeg;base64,";

const NAV_ITEMS = [
  { icon: "⊞",  label: "Dashboard",      id: "dashboard" },
  { icon: "📍", label: "Sites",           id: "sites" },
  { icon: "📋", label: "Expenses",        id: "expenses" },
  { icon: "👷", label: "Labour Tracking", id: "labour" },
  { icon: "📊", label: "Reports",         id: "reports" },
  { icon: "⚙️", label: "Settings",        id: "settings" },
];

const EXPENSE_CATEGORIES = [
  "Materials","Labour","Equipment","Transportation",
  "Utilities","Permits & Fees","Other",
];

export default function ExpenseEntry() {
  const [activeNav, setActiveNav]       = useState("expenses");
  const [dragOver, setDragOver]         = useState(false);
  const [uploadedFile, setUploadedFile] = useState(null);
  const [form, setForm] = useState({
    siteName:"", expenseCategory:"", date:"", amount:"", description:"",
  });
  const [errors, setErrors] = useState({});

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(f => ({ ...f, [name]: value }));
    if (errors[name]) setErrors(err => ({ ...err, [name]: "" }));
  };

  const validate = () => {
    const v = {};
    if (!form.siteName.trim())    v.siteName        = "Site name is required";
    if (!form.expenseCategory)    v.expenseCategory  = "Category is required";
    if (!form.date)               v.date             = "Date is required";
    if (!form.amount || isNaN(form.amount) || Number(form.amount) <= 0)
                                  v.amount           = "Enter a valid amount";
    if (!form.description.trim()) v.description      = "Description is required";
    if (!uploadedFile)            v.bill             = "Please upload a bill";
    return v;
  };

  const handleSave = () => {
    const v = validate();
    if (Object.keys(v).length) { setErrors(v); return; }
    alert("Expense saved successfully!");
    handleCancel();
  };

  const handleCancel = () => {
    setForm({ siteName:"", expenseCategory:"", date:"", amount:"", description:"" });
    setUploadedFile(null);
    setErrors({});
  };

  const handleFileDrop = (e) => {
    e.preventDefault();
    setDragOver(false);
    const file = e.dataTransfer?.files?.[0] || e.target?.files?.[0];
    if (!file) return;
    if (!["image/jpeg","image/png","application/pdf"].includes(file.type)) {
      setErrors(err => ({ ...err, bill:"Only JPG, PNG, PDF allowed" }));
      return;
    }
    if (file.size > 10 * 1024 * 1024) {
      setErrors(err => ({ ...err, bill:"File must be under 10 MB" }));
      return;
    }
    setUploadedFile(file);
    setErrors(err => ({ ...err, bill:"" }));
  };

  return (
    <div style={s.shell}>

      {/* ── LEFT SIDEBAR (dark, same as login page left panel) ── */}
      <aside style={s.sidebar}>
        <div style={s.logoBox}>
          <img src={LOGO_SRC} alt="BuildTrack" style={s.logoImg} />
        </div>

        <nav style={s.nav}>
          {NAV_ITEMS.map(item => (
            <button
              key={item.id}
              style={{ ...s.navItem, ...(activeNav===item.id ? s.navActive : {}) }}
              onClick={() => setActiveNav(item.id)}
            >
              <span style={s.navIcon}>{item.icon}</span>
              <span>{item.label}</span>
              {activeNav===item.id && <span style={s.activeDot} />}
            </button>
          ))}
        </nav>

        <div style={s.sideFooter}>
          <div style={s.sideDivider} />
          <div style={s.userCard}>
            <div style={s.userAv}>JC</div>
            <div>
              <div style={s.userName}>John Carter</div>
              <div style={s.userSub}>Project Manager</div>
            </div>
          </div>
        </div>
      </aside>

      {/* ── RIGHT: WHITE CONTENT AREA ── */}
      <div style={s.content}>

        {/* ── TOPBAR (white, matches dashboard topbar) ── */}
        <header style={s.topbar}>
          <div style={s.topLeft}>
            <span style={s.topBrand}>Track</span>
            <span style={s.topBadge}>🛡 EXPENSE PORTAL</span>
          </div>
          <div style={s.topRight}>
            <div style={s.topUser}>
              <div style={s.topAv}>JC</div>
              <div>
                <div style={s.topName}>John Carter</div>
                <div style={s.topRole}>Project Manager</div>
              </div>
            </div>
            <button style={s.logoutBtn}>↪ Logout</button>
          </div>
        </header>

        {/* ── HERO BANNER (dark, same as dashboard) ── */}
        <div style={s.hero}>
          <div>
            <div style={s.heroEye}>CURRENTLY ACTIVE</div>
            <h1 style={s.heroTitle}>Add New Expense Entry</h1>
            <p style={s.heroSub}>
              Log expenditures for your construction project · BuildTrack Finance Module
            </p>
          </div>
          <button style={s.exportBtn}>↓ Export Expense Report</button>
        </div>

        {/* ── STAT CARDS (white, same style as dashboard) ── */}
        <div style={s.statsRow}>
          {[
            { label:"TOTAL BUDGET",   value:"₹5.00 Crores",  sub:"Sanctioned project limit",  bar:"100%", color:"#F5A623" },
            { label:"SPENT TO DATE",  value:"₹4.20 Crores",  sub:"84% capital utilised",       bar:"84%",  color:"#22C55E" },
            { label:"REMAINING",      value:"₹80.00 Lakhs",  sub:"Available for new expenses", bar:"16%",  color:"#3B82F6" },
          ].map((st, i) => (
            <div key={i} style={s.statCard}>
              <div style={s.statHead}>
                <span style={s.statLabel}>{st.label}</span>
                <span style={{ color:st.color, fontSize:16 }}>
                  {i===0?"$":i===1?"✓":"⏱"}
                </span>
              </div>
              <div style={{ ...s.statVal, color:st.color }}>{st.value}</div>
              <div style={s.statSub}>{st.sub}</div>
              <div style={s.barBg}>
                <div style={{ ...s.barFill, width:st.bar, background:st.color }} />
              </div>
            </div>
          ))}
        </div>

        {/* ── FORM CARD (white, matches dashboard card style) ── */}
        <div style={s.formWrap}>
          <div style={s.formCard}>

            {/* card header */}
            <div style={s.cardHead}>
              <div style={s.cardEye}>EXPENSE ENTRY FORM</div>
              <h2 style={s.cardTitle}>Add Expense Details</h2>
              <p style={s.cardSub}>All fields marked * are required</p>
            </div>

            {/* 2-col grid */}
            <div style={s.grid2}>
              <F label="Site Name" err={errors.siteName}>
                <input style={{ ...s.inp, ...(errors.siteName ? s.inpErr:{}) }}
                  name="siteName" placeholder="e.g. Skyline Heights Phase 1"
                  value={form.siteName} onChange={handleChange} />
              </F>

              <F label="Expense Category" err={errors.expenseCategory}>
                <select style={{ ...s.inp, ...(errors.expenseCategory ? s.inpErr:{}) }}
                  name="expenseCategory" value={form.expenseCategory} onChange={handleChange}>
                  <option value="">Select Category</option>
                  {EXPENSE_CATEGORIES.map(c=><option key={c} value={c}>{c}</option>)}
                </select>
              </F>

              <F label="Date" err={errors.date}>
                <input style={{ ...s.inp, ...(errors.date ? s.inpErr:{}) }}
                  name="date" type="date"
                  value={form.date} onChange={handleChange} />
              </F>

              <F label="Amount (₹)" err={errors.amount}>
                <div style={{ position:"relative" }}>
                  <span style={s.rupee}>₹</span>
                  <input style={{ ...s.inp, ...(errors.amount ? s.inpErr:{}), paddingLeft:28 }}
                    name="amount" type="number" placeholder="0.00"
                    value={form.amount} onChange={handleChange} />
                </div>
              </F>
            </div>

            {/* description */}
            <div style={{ marginTop:20 }}>
              <F label="Description" err={errors.description}>
                <textarea style={{ ...s.inp, ...(errors.description ? s.inpErr:{}), minHeight:88, resize:"vertical" }}
                  name="description" placeholder="Describe this expense in detail..."
                  value={form.description} onChange={handleChange} />
              </F>
            </div>

            {/* upload */}
            <div style={{ marginTop:20 }}>
              <div style={s.fLabel}>Upload Bill / Receipt <span style={{color:"#F5A623"}}>*</span></div>
              <label
                style={{
                  ...s.drop,
                  ...(dragOver    ? s.dropActive : {}),
                  ...(errors.bill ? s.dropErr    : {}),
                }}
                onDragOver={e=>{ e.preventDefault(); setDragOver(true); }}
                onDragLeave={()=>setDragOver(false)}
                onDrop={handleFileDrop}
              >
                <input type="file" accept=".jpg,.jpeg,.png,.pdf"
                  style={{display:"none"}} onChange={handleFileDrop} />
                {uploadedFile ? (
                  <div style={{display:"flex",alignItems:"center",gap:10}}>
                    <span style={{fontSize:22}}>📎</span>
                    <span style={{fontSize:13,color:"#374151"}}>{uploadedFile.name}</span>
                    <button style={s.rmBtn}
                      onClick={e=>{ e.preventDefault(); setUploadedFile(null); }}>✕</button>
                  </div>
                ) : (
                  <>
                    <div style={{fontSize:30,marginBottom:8,color:"#94A3B8"}}>⬆</div>
                    <div style={{fontSize:13,color:"#6B7280"}}>
                      <span style={{color:"#F5A623",fontWeight:600}}>Click to upload</span>
                      &nbsp;or drag and drop
                    </div>
                    <div style={{fontSize:11,color:"#9CA3AF",marginTop:4}}>
                      JPG, PNG, PDF · Max 10 MB
                    </div>
                  </>
                )}
              </label>
              {errors.bill && <div style={s.errTxt}>{errors.bill}</div>}
            </div>

            <div style={s.hrLine} />

            {/* actions */}
            <div style={s.actions}>
              <button style={s.cancelBtn} onClick={handleCancel}>Cancel</button>
              <button style={s.saveBtn}   onClick={handleSave}>→ Save Expense</button>
            </div>

          </div>
        </div>
      </div>
    </div>
  );
}

/* tiny field wrapper */
function F({ label, err, children }) {
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:5 }}>
      <label style={s.fLabel}>
        {label} <span style={{color:"#F5A623"}}>*</span>
      </label>
      {children}
      {err && <span style={s.errTxt}>{err}</span>}
    </div>
  );
}

/* ── tokens ── */
