const DARK2  = "#161B27";
const DBORD  = "rgba(255,255,255,0.08)";
const ORANGE = "#F5A623";
const WHITE  = "#FFFFFF";
const GREY   = "#F8FAFC";
const BORD   = "#E5E7EB";
const TEXT   = "#111827";
const MUTED  = "#6B7280";

const s = {
  /* layout */
  shell:{
    display:"flex", minHeight:"100vh",
    fontFamily:"'Inter','Segoe UI',system-ui,sans-serif",
    background:GREY,
  },

  /* ── dark sidebar (matches login page left panel) ── */
  sidebar:{
    width:230, minHeight:"100vh",
    background:DARK2,
    borderRight:`1px solid ${DBORD}`,
    display:"flex", flexDirection:"column", flexShrink:0,
  },
  logoBox:{
    padding:"20px 18px 16px",
    borderBottom:`1px solid ${DBORD}`,
  },
  logoImg:{ width:"100%", maxWidth:160, objectFit:"contain" },
  nav:{ flex:1, padding:"14px 8px" },
  navItem:{
    display:"flex", alignItems:"center", gap:10,
    width:"100%", padding:"10px 12px", borderRadius:8,
    background:"transparent", border:"none",
    cursor:"pointer", fontSize:13.5, color:"#94A3B8",
    fontWeight:500, textAlign:"left", position:"relative",
    marginBottom:3, transition:"background 0.15s,color 0.15s",
  },
  navActive:{ background:"rgba(245,166,35,0.12)", color:ORANGE, fontWeight:600 },
  navIcon:{ fontSize:14, width:18, textAlign:"center", flexShrink:0 },
  activeDot:{
    position:"absolute", right:12, top:"50%", transform:"translateY(-50%)",
    width:6, height:6, borderRadius:"50%", background:ORANGE,
  },
  sideFooter:{ padding:"0 8px 20px" },
  sideDivider:{ borderTop:`1px solid ${DBORD}`, margin:"10px 0" },
  userCard:{
    display:"flex", alignItems:"center", gap:10,
    padding:"10px 12px", borderRadius:8,
    background:"rgba(255,255,255,0.04)",
  },
  userAv:{
    width:34, height:34, borderRadius:"50%",
    background:`linear-gradient(135deg,${ORANGE},#E08B00)`,
    display:"flex", alignItems:"center", justifyContent:"center",
    fontWeight:700, fontSize:13, color:WHITE, flexShrink:0,
  },
  userName:{ fontSize:13, fontWeight:600, color:"#E2E8F0" },
  userSub:{ fontSize:11, color:"#64748B" },

  /* ── white content area ── */
  content:{
    flex:1, display:"flex", flexDirection:"column", minWidth:0,
    background:WHITE,
  },

  /* topbar — white, matches dashboard topbar exactly */
  topbar:{
    display:"flex", alignItems:"center", justifyContent:"space-between",
    padding:"0 28px", height:58, background:WHITE,
    borderBottom:`1px solid ${BORD}`,
    boxShadow:"0 1px 3px rgba(0,0,0,0.04)",
  },
  topLeft:{ display:"flex", alignItems:"center", gap:14 },
  topBrand:{ fontSize:18, fontWeight:700, color:ORANGE, letterSpacing:-0.5 },
  topBadge:{
    fontSize:11, fontWeight:600, color:MUTED,
    border:`1px solid ${BORD}`, borderRadius:20,
    padding:"3px 10px", letterSpacing:0.5,
    background:GREY,
  },
  topRight:{ display:"flex", alignItems:"center", gap:16 },
  topUser:{ display:"flex", alignItems:"center", gap:10 },
  topAv:{
    width:32, height:32, borderRadius:"50%",
    background:`linear-gradient(135deg,${ORANGE},#E08B00)`,
    display:"flex", alignItems:"center", justifyContent:"center",
    fontWeight:700, fontSize:12, color:WHITE,
  },
  topName:{ fontSize:13, fontWeight:600, color:TEXT },
  topRole:{ fontSize:11, color:MUTED },
  logoutBtn:{
    background:"transparent", border:`1px solid ${BORD}`,
    borderRadius:8, padding:"6px 14px",
    fontSize:12, color:MUTED, cursor:"pointer",
  },

  /* hero banner — dark, matches dashboard hero exactly */
  hero:{
    margin:"24px 28px 0",
    background:`linear-gradient(135deg,${DARK} 0%,${DARK2} 100%)`,
    borderRadius:14, padding:"24px 28px",
    display:"flex", alignItems:"center",
    justifyContent:"space-between",
  },
  heroEye:{
    fontSize:11, fontWeight:700, color:ORANGE,
    letterSpacing:1.2, marginBottom:6,
  },
  heroTitle:{
    fontSize:22, fontWeight:700, color:WHITE,
    margin:"0 0 4px",
  },
  heroSub:{ fontSize:13, color:"#94A3B8", margin:0 },
  exportBtn:{
    background:"rgba(255,255,255,0.07)",
    border:`1px solid ${DBORD}`,
    borderRadius:10, padding:"10px 18px",
    fontSize:13, fontWeight:600, color:WHITE,
    cursor:"pointer", whiteSpace:"nowrap",
  },

  /* stat cards — white, matches dashboard cards */
  statsRow:{
    display:"grid", gridTemplateColumns:"repeat(3,1fr)",
    gap:16, margin:"20px 28px 0", padding:"0",
  },
  statCard:{
    background:WHITE, borderRadius:12, padding:"20px 22px",
    border:`1px solid ${BORD}`,
    boxShadow:"0 1px 3px rgba(0,0,0,0.06)",
  },
  statHead:{
    display:"flex", justifyContent:"space-between",
    alignItems:"center", marginBottom:8,
  },
  statLabel:{ fontSize:11, fontWeight:700, color:"#64748B", letterSpacing:0.8 },
  statVal:{ fontSize:22, fontWeight:700, marginBottom:4 },
  statSub:{ fontSize:12, color:MUTED, marginBottom:10 },
  barBg:{ height:4, background:"#F1F5F9", borderRadius:99, overflow:"hidden" },
  barFill:{ height:"100%", borderRadius:99 },

  /* form */
  formWrap:{ padding:"20px 28px 36px" },
  formCard:{
    background:WHITE, borderRadius:14, padding:"28px 30px",
    border:`1px solid ${BORD}`,
    boxShadow:"0 1px 3px rgba(0,0,0,0.06)",
  },
  cardHead:{
    marginBottom:22, paddingBottom:18,
    borderBottom:`1px solid ${BORD}`,
  },
  cardEye:{
    fontSize:10, fontWeight:700, color:ORANGE,
    letterSpacing:1.4, marginBottom:4,
  },
  cardTitle:{ fontSize:18, fontWeight:700, color:TEXT, margin:"0 0 3px" },
  cardSub:{ fontSize:12, color:MUTED, margin:0 },

  grid2:{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"18px 24px" },

  fLabel:{ fontSize:12, fontWeight:600, color:"#374151" },
  inp:{
    width:"100%", padding:"10px 12px",
    border:`1.5px solid ${BORD}`,
    borderRadius:8, fontSize:13.5, color:TEXT,
    outline:"none", background:GREY,
    boxSizing:"border-box",
    transition:"border-color 0.15s",
  },
  inpErr:{ borderColor:"#EF4444" },
  errTxt:{ fontSize:11, color:"#EF4444", marginTop:2 },
  rupee:{
    position:"absolute", left:10, top:"50%",
    transform:"translateY(-50%)",
    color:MUTED, fontSize:14, pointerEvents:"none",
  },

  drop:{
    display:"flex", flexDirection:"column",
    alignItems:"center", justifyContent:"center",
    border:`2px dashed ${BORD}`, borderRadius:10,
    padding:"32px 20px", cursor:"pointer",
    background:GREY, minHeight:116,
    transition:"border-color 0.15s, background 0.15s",
    marginTop:6,
  },
  dropActive:{ borderColor:ORANGE, background:"#FFFBF0" },
  dropErr:{ borderColor:"#EF4444" },
  rmBtn:{
    background:"none", border:"none", cursor:"pointer",
    color:MUTED, fontSize:16, padding:"0 4px",
  },

  hrLine:{ borderTop:`1px solid ${BORD}`, margin:"24px 0" },

  actions:{ display:"flex", justifyContent:"space-between", alignItems:"center" },
  cancelBtn:{
    padding:"11px 28px", border:`1.5px solid ${BORD}`,
    borderRadius:9, background:"transparent",
    fontSize:14, fontWeight:600, color:MUTED, cursor:"pointer",
  },
  saveBtn:{
    padding:"11px 36px", border:"none", borderRadius:9,
    background:`linear-gradient(135deg,${ORANGE},#E08B00)`,
    fontSize:14, fontWeight:700, color:WHITE, cursor:"pointer",
    boxShadow:"0 4px 14px rgba(245,166,35,0.35)",
  },
};
